begin;
alter table public.leads add column if not exists canonical_lead_id uuid references public.leads(id) on delete restrict,add column if not exists duplicate_state text not null default 'canonical' check(duplicate_state in('canonical','suspected','merged')),add column if not exists merged_at timestamptz,add column if not exists merged_by uuid references public.profiles(id);update public.leads set canonical_lead_id=id where canonical_lead_id is null;create index if not exists leads_canonical_identity_idx on public.leads(organization_id,canonical_lead_id,duplicate_state);create index if not exists leads_duplicate_detection_idx on public.leads(organization_id,phone_normalized,email_normalized,duplicate_state);
create table if not exists public.lead_identity_merge_events(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,canonical_lead_id uuid not null references public.leads(id) on delete restrict,merged_lead_ids uuid[] not null,actor_id uuid not null references public.profiles(id),reason text not null check(char_length(reason) between 10 and 500),ownership_snapshot jsonb not null,source_snapshot jsonb not null,created_at timestamptz not null default now());alter table public.lead_identity_merge_events enable row level security;drop policy if exists lead_identity_merge_events_scope on public.lead_identity_merge_events;create policy lead_identity_merge_events_scope on public.lead_identity_merge_events for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(canonical_lead_id)));revoke all on public.lead_identity_merge_events from anon;revoke insert,update,delete on public.lead_identity_merge_events from authenticated;grant select on public.lead_identity_merge_events to authenticated;
create or replace function public.merge_duplicate_lead_identity(p_actor_id uuid,p_organization_id uuid,p_canonical_lead_id uuid,p_duplicate_lead_ids uuid[],p_reason text)returns jsonb language plpgsql security definer set search_path='' as $$declare actor_role text;master public.leads;candidate public.leads;all_ids uuid[];owners jsonb:='[]'::jsonb;sources jsonb:='[]'::jsonb;merged integer:=0;begin select coalesce(commercial_role,case role when'admin'then'director'else role end)into actor_role from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true;if actor_role not in('director','superintendent')then raise exception 'lead_merge_actor_forbidden';end if;if char_length(trim(coalesce(p_reason,'')))<10 or coalesce(array_length(p_duplicate_lead_ids,1),0)<1 or p_canonical_lead_id=any(p_duplicate_lead_ids)then raise exception 'lead_merge_payload_invalid';end if;select * into master from public.leads where id=p_canonical_lead_id and organization_id=p_organization_id for update;if master.id is null or master.duplicate_state='merged'then raise exception 'lead_merge_master_invalid';end if;perform pg_advisory_xact_lock(hashtextextended(p_organization_id::text||':'||coalesce(master.identity_key,master.id::text),0));all_ids:=array[p_canonical_lead_id]||p_duplicate_lead_ids;for candidate in select * from public.leads where organization_id=p_organization_id and id=any(p_duplicate_lead_ids)for update loop if candidate.duplicate_state='merged'or not(candidate.phone_normalized is not null and candidate.phone_normalized=master.phone_normalized or candidate.email_normalized is not null and candidate.email_normalized=master.email_normalized)then raise exception 'lead_merge_identity_mismatch:%',candidate.id;end if;owners:=owners||jsonb_build_array(jsonb_build_object('leadId',candidate.id,'assignedTo',candidate.assigned_to));sources:=sources||jsonb_build_array(jsonb_build_object('leadId',candidate.id,'source',candidate.source,'createdAt',candidate.created_at,'status',candidate.status));update public.leads set canonical_lead_id=master.id,duplicate_state='merged',status='arquivado',merged_at=now(),merged_by=p_actor_id,metadata=coalesce(metadata,'{}'::jsonb)||jsonb_build_object('duplicateOf',master.id,'duplicateMergeReason',trim(p_reason),'originalAssignedTo',candidate.assigned_to,'originalStatus',candidate.status)where id=candidate.id;merged:=merged+1;end loop;if merged<>array_length(p_duplicate_lead_ids,1)then raise exception 'lead_merge_candidate_missing';end if;update public.leads set canonical_lead_id=id,duplicate_state='canonical',metadata=coalesce(metadata,'{}'::jsonb)||jsonb_build_object('mergedIdentityCount',merged,'identityMergedAt',now())where id=master.id;insert into public.lead_identity_merge_events(organization_id,canonical_lead_id,merged_lead_ids,actor_id,reason,ownership_snapshot,source_snapshot)values(p_organization_id,master.id,p_duplicate_lead_ids,p_actor_id,trim(p_reason),owners,sources);return jsonb_build_object('canonicalLeadId',master.id,'merged',merged,'singleActiveRecord',true,'historyPreserved',true,'ownershipPreservedInSnapshot',true,'automaticMerge',false,'auditable',true);end $$;
revoke all on function public.merge_duplicate_lead_identity(uuid,uuid,uuid,uuid[],text)from public,anon,authenticated;grant execute on function public.merge_duplicate_lead_identity(uuid,uuid,uuid,uuid[],text)to service_role;
commit;
